function renderContractorsPage(){if(contractorsLoading&&!contractorsData.records.length){renderContractorsLoadingPage();return}var visible=getVisibleContractorRecords();var selected=contractorsData.records[contractorsData.selectedIndex]||visible[0]||contractorsData.records[0]||{};var metrics=getContractorMetricStats(contractorsData.records);pagePanel.className="page-panel contractors-page";pagePanel.innerHTML=renderModuleStatusLine(contractorsLoading?'Refreshing...':contractorsLastUpdated?'Updated '+contractorsLastUpdated:(contractorsLoadError||''))+'<div class="contractors-metrics">'+metrics.map(function(metric){return '<button type="button" class="contractor-metric-button '+(activeContractorMetric===metric.key?'active':'')+'" data-contractor-metric="'+escapeHtml(metric.key)+'"><span>'+escapeHtml(metric.label)+'</span><strong>'+escapeHtml(metric.value)+'</strong><em>'+escapeHtml(metric.note)+'</em></button>'}).join('')+'</div><section class="contractors-filter-card"><div><h3>Filters + Sort + Search</h3><p>Refine contractor records the same way on every page</p></div><button type="button" data-contractor-report>Reports</button><div class="contractors-filters"><label>Documents<select data-contractor-filter="documents">'+renderSelectOptions('All documents',CONTRACTOR_DOCUMENT_OPTIONS,contractorFilters.documents)+'</select></label><label>Risk<select data-contractor-filter="risk">'+renderSelectOptions('All risks',CONTRACTOR_RISK_OPTIONS,contractorFilters.risk)+'</select></label><label>Region<select data-contractor-filter="region">'+renderSelectOptions('All regions',getContractorRegions(),contractorFilters.region)+'</select></label><label>Sort<select data-contractor-filter="sort"><option'+(contractorFilters.sort==='Highest risk'?' selected':'')+'>Highest risk</option><option'+(contractorFilters.sort==='Expiring soon'?' selected':'')+'>Expiring soon</option><option'+(contractorFilters.sort==='Name A-Z'?' selected':'')+'>Name A-Z</option></select></label><label>Search<input data-contractor-filter="search" type="search" placeholder="Search contractors" value="'+escapeHtml(contractorFilters.search)+'"></label></div></section><div class="contractors-workspace"><section class="contractors-records"><div class="contractors-section-head"><div><h3>Records</h3><p>Review contractor compliance, document status, and workflow.</p></div><strong>'+escapeHtml(visible.length)+' showing</strong></div><div class="contractors-table"><div class="contractors-table-head"><span>Contractor</span><span>Regions</span><span>Documents</span><span>Risk</span><span>GL Exp.</span><span>WC Exp.</span></div>'+visible.map(function(record){var index=contractorsData.records.indexOf(record);return '<button type="button" class="contractors-row'+(index===contractorsData.selectedIndex?' active':'')+'" data-contractor-index="'+index+'"><span><strong>'+escapeHtml(record.name)+'</strong><em>'+escapeHtml(record.phone)+'</em></span><span>'+escapeHtml(record.region)+'</span><span><mark>'+escapeHtml(record.documents)+'</mark></span><span><mark class="stage-'+(contractorRiskScore(record)>=70?'critical':contractorRiskScore(record)>=50?'review':'monitor')+'">'+escapeHtml(record.risk)+'</mark></span><span>'+escapeHtml(record.glExpiry)+'</span><span>'+escapeHtml(record.wcExpiry)+'</span></button>'}).join('')+'</div></section><aside class="contractors-detail"><div class="contractors-detail-head"><div><span>Selected contractor</span><h3>'+escapeHtml(selected.name)+'</h3><p>'+escapeHtml(selected.documents)+' / '+escapeHtml(selected.risk)+'</p></div></div><div class="contractors-detail-grid"><article><span>Regions</span><strong>'+escapeHtml(selected.region)+'</strong></article><article><span>Phone</span><strong>'+escapeHtml(selected.phone)+'</strong></article><article><span>Email</span><strong>'+escapeHtml(selected.email)+'</strong></article><article><span>Address</span><strong>'+escapeHtml(selected.address)+'</strong></article><article><span>GL Expiry</span><strong>'+escapeHtml(selected.glExpiry)+'</strong></article><article><span>WC Expiry</span><strong>'+escapeHtml(selected.wcExpiry)+'</strong></article><article><span>Next Action</span><strong>'+escapeHtml(selected.nextAction)+'</strong></article></div><section class="contractors-workflow"><div class="card-heading"><h3>Citadel Workflow</h3><span>Protected from source imports</span></div><div class="workspace-status">'+escapeHtml(contractorWorkspaceStatus)+'</div><form class="liens-quick-add" data-contractor-workspace="note"><label>Note<textarea name="note_text" rows="2" placeholder="Add a protected contractor note"></textarea></label><button type="submit">Save Note</button></form><form class="liens-quick-add" data-contractor-workspace="alert"><label>Alert<input name="alert_text" placeholder="What needs attention?"></label><label>Due<input name="due_date" type="date"></label><button type="submit">Set Alert</button></form><form class="liens-quick-add" data-contractor-workspace="followup"><label>Follow-up<input name="followup_text" placeholder="Next action"></label><label>Assigned<input name="assigned_to" value="Carlynn"></label><label>Due<input name="due_date" type="date"></label><button type="submit">Add Follow-up</button></form><div class="liens-workspace-feed"><h4>Recent Notes</h4>'+renderLienWorkspaceList(getContractorWorkspaceItems('notes',selected.id),'No notes yet.',[{key:'note_text',strong:true},{key:'note_by',fallback:'Team'},{key:'note_date'}])+'<h4>Open Alerts</h4>'+renderLienWorkspaceList(getContractorWorkspaceItems('alerts',selected.id),'No alerts yet.',[{key:'alert_text',strong:true},{key:'owner',fallback:'Carlynn'},{key:'due_date'}])+'<h4>Follow-ups</h4>'+renderLienWorkspaceList(getContractorWorkspaceItems('followUps',selected.id),'No follow-ups yet.',[{key:'followup_text',strong:true},{key:'assigned_to',fallback:'Carlynn'},{key:'due_date'}])+'</div></section></aside></div>'}
