function bindContractorsPage(){if(contractorsPageEventsBound)return;contractorsPageEventsBound=true;pagePanel.addEventListener("click",function(event){if(activePage!=="contractors")return;var metric=event.target.closest("[data-contractor-metric]");if(metric){activeContractorMetric=metric.getAttribute("data-contractor-metric")||"total";contractorsData.selectedIndex=0;renderContractorsPage();return}if(event.target.closest("[data-contractor-report]")){openContractorReportsModal();return}var row=event.target.closest("[data-contractor-index]");if(!row)return;contractorsData.selectedIndex=Number(row.getAttribute("data-contractor-index"));renderContractorsPage()});pagePanel.addEventListener("submit",function(event){if(activePage!=="contractors")return;var form=event.target.closest("[data-contractor-workspace]");if(!form)return;event.preventDefault();var selected=contractorsData.records[contractorsData.selectedIndex]||{};var data=new FormData(form);var type=form.getAttribute("data-contractor-workspace");var payload={contractor_id:selected.id};data.forEach(function(value,key){payload[key]=value});if(type==="note")saveContractorWorkspace("saveContractorNote",payload);if(type==="alert")saveContractorWorkspace("saveContractorAlert",payload);if(type==="followup")saveContractorWorkspace("saveContractorFollowUp",payload)});pagePanel.addEventListener("change",function(event){if(activePage!=="contractors")return;var field=event.target.closest("select[data-contractor-filter]");if(!field)return;contractorFilters[field.getAttribute("data-contractor-filter")]=field.value;contractorsData.selectedIndex=0;renderContractorsPage()});pagePanel.addEventListener("input",function(event){if(activePage!=="contractors")return;var search=event.target.closest("input[data-contractor-filter='search']");if(!search)return;contractorFilters.search=search.value;window.clearTimeout(contractorSearchTimer);contractorSearchTimer=window.setTimeout(function(){contractorsData.selectedIndex=0;renderContractorsPage();var next=pagePanel.querySelector("input[data-contractor-filter='search']");if(next){next.focus();next.setSelectionRange(next.value.length,next.value.length)}},180)})}
function saveContractorWorkspace(action,payload){contractorWorkspaceStatus="Saving...";if(activePage==="contractors")renderContent();var params=Object.keys(payload).map(function(key){return encodeURIComponent(key)+"="+encodeURIComponent(payload[key]||"")}).join("&");return jsonp(CITADEL_API_URL+"?action="+encodeURIComponent(action)+"&"+params).then(function(response){if(!response||!response.ok)throw new Error(response&&response.error?response.error:"Save failed");contractorWorkspaceStatus="Saved";return loadContractorsData()}).catch(function(error){contractorWorkspaceStatus="Save failed";console.warn("Contractors workspace save failed",error);if(activePage==="contractors")renderContent()})}


