function renderRegistrationsPage(){var readOnly=isRegistrationRegionView();var mode=getRegistrationMode();var rows=getVisibleRegistrationRequests();var selected=registrationsData.requests[registrationsData.selectedIndex]||rows[0]||{};var metrics=getRegistrationMetrics();var isForm=mode==='request';var heading=isForm?'Submit Registration / License Request':mode==='archived'?'Archived Registrations/Licenses':mode==='active'?'Active Registrations/Licenses':'Open Requests';if(isForm){pagePanel.className='page-panel registration-page registration-form-page';pagePanel.innerHTML=renderModuleStatusLine(registrationsLoading?'Refreshing...':(registrationsLoadStatus||registrationsData.lastUpdated&&('Updated '+registrationsData.lastUpdated)||'Ready'))+'<section class="registration-shell">'+renderRegistrationForm()+'</section>';return}pagePanel.className='page-panel registration-page registration-workflow-page liens-page';pagePanel.innerHTML=renderModuleStatusLine(registrationsLoading?'Refreshing...':(registrationsLoadStatus||registrationsData.lastUpdated&&('Updated '+registrationsData.lastUpdated)||'Ready'))+'<div class="liens-metrics registration-metrics">'+metrics.map(function(metric){var hide=(mode==='open'&&metric.key==='archived')||(mode==='active'&&metric.key==='archived')||(mode==='archived'&&metric.key!=='archived'&&metric.key!=='all');if(hide)return '';return '<button type="button" class="lien-metric-button '+(activeRegistrationMetric===metric.key?'active':'')+'" data-registration-metric="'+escapeHtml(metric.key)+'"><span>'+escapeHtml(metric.label)+'</span><strong>'+escapeHtml(metric.value)+'</strong><em>'+escapeHtml(metric.note)+'</em></button>'}).join('')+'</div><section class="liens-filter-card registration-filter-card"><div><h3>Filters + Sort + Search</h3><p>Track registration requests from intake through completion.</p></div><button type="button" data-registration-report>Reports</button><div class="liens-filters"><label>Stage<select data-registration-filter="stage">'+renderSelectOptions('All stages',registrationStages(),registrationFilters.stage)+'</select></label><label>Region<select data-registration-filter="region">'+renderSelectOptions('All regions',registrationRegionOptions(),registrationFilters.region)+'</select></label><label>Search<input data-registration-filter="search" type="search" placeholder="Search requests" value="'+escapeHtml(registrationFilters.search)+'"></label></div></section><div class="liens-workspace registration-workspace '+(readOnly?'is-read-only':'')+'"><section class="liens-records"><div class="liens-section-head"><div><h3>'+escapeHtml(heading)+'</h3><p>Emma works requests through research, submitted, follow up, active, and archive.</p></div><strong>'+escapeHtml(rows.length)+' showing</strong></div>'+renderRegistrationRows(rows)+'</section>'+(readOnly?'':renderRegistrationDetail(selected,mode==='archived'))+'</div>'}function bindRegistrationsPage(){if(registrationsPageEventsBound)return;registrationsPageEventsBound=true;pagePanel.addEventListener('click',function(event){if(activePage.indexOf('registration')!==0)return;var metric=event.target.closest('[data-registration-metric]');if(metric){activeRegistrationMetric=metric.getAttribute('data-registration-metric')||'all';registrationsData.selectedIndex=0;renderRegistrationsPage();return}var view=event.target.closest('[data-registration-view]');if(view){registrationDetailView=view.getAttribute('data-registration-view')||'info';renderRegistrationsPage();return}var row=event.target.closest('[data-registration-index]');if(row){registrationsData.selectedIndex=Number(row.getAttribute('data-registration-index'));registrationDetailView='info';renderRegistrationsPage();return}var choice=event.target.closest('[data-registration-field]');if(choice){var selectedChoice=registrationsData.requests[registrationsData.selectedIndex]||{};var fieldPayload={request_id:selectedChoice.id};fieldPayload[choice.getAttribute('data-registration-field')]=choice.getAttribute('data-registration-value');updateRegistrationRequest(fieldPayload);return}var action=event.target.closest('[data-registration-action]');if(action){runRegistrationAction(action.getAttribute('data-registration-action'));return}if(event.target.closest('[data-registration-report]')){openWorkspaceReportsModal('Registrations Reports','Export registration workflow requests from the current filtered view.',getVisibleRegistrationRequests().length,function(format){var table=[['Request ID','Submitted','Requestor','Brand','Region','Jurisdiction','Stage','Status','Assigned To','Requirements']].concat(getVisibleRegistrationRequests().map(function(row){return [row.id,row.submittedAt,row.requestor,row.brand,row.region,row.jurisdiction,row.stage,row.status,row.assignedTo,row.requirements]}));reportDownloadTable(table,format,'citadel-registrations-report')});return}});pagePanel.addEventListener('change',function(event){if(activePage.indexOf('registration')!==0)return;var requestField=event.target.closest('#registrationRequestForm select, #registrationRequestForm input, #registrationRequestForm textarea');if(requestField){updateRegistrationRequestDraft(requestField.form);return}var filter=event.target.closest('select[data-registration-filter]');if(filter){registrationFilters[filter.getAttribute('data-registration-filter')]=filter.value;registrationsData.selectedIndex=0;renderRegistrationsPage();return}var stage=event.target.closest('select[data-registration-stage]');if(stage){updateRegistrationRequest({request_id:stage.getAttribute('data-registration-stage'),stage:stage.value,status:'Open',assigned_to:'Emma'});return}});pagePanel.addEventListener('input',function(event){if(activePage.indexOf('registration')!==0)return;var requestField=event.target.closest('#registrationRequestForm input, #registrationRequestForm textarea');if(requestField){updateRegistrationRequestDraft(requestField.form);return}var search=event.target.closest('input[data-registration-filter="search"]');if(!search)return;registrationFilters.search=search.value;registrationsData.selectedIndex=0;renderRegistrationsPage();var next=pagePanel.querySelector('input[data-registration-filter="search"]');if(next){next.focus();next.setSelectionRange(next.value.length,next.value.length)}});pagePanel.addEventListener('submit',function(event){if(activePage.indexOf('registration')!==0)return;var form=event.target.closest('#registrationRequestForm');if(!form)return;event.preventDefault();saveRegistrationRequestFromForm(form)});pagePanel.addEventListener('reset',function(event){if(activePage.indexOf('registration')!==0)return;window.setTimeout(function(){registrationRequestDraft={};registrationRequestStatus='';renderRegistrationsPage()},0)})}
function showSubmissionToast(message){var old=document.querySelector('.citadel-toast');if(old)old.remove();var toast=document.createElement('div');toast.className='citadel-toast';toast.textContent=message;document.body.appendChild(toast);window.setTimeout(function(){toast.classList.add('is-visible')},20);window.setTimeout(function(){toast.classList.remove('is-visible');window.setTimeout(function(){if(toast&&toast.parentNode)toast.parentNode.removeChild(toast)},260)},3600)}
function saveRegistrationRequestFromForm(form){if(!CITADEL_API_URL){registrationRequestStatus='Registration sheet is not connected yet';renderRegistrationsPage();return}var data=new FormData(form);var payload={};data.forEach(function(value,key){payload[key]=value});payload.client_submitted_at=new Date().toISOString();payload.status='New';payload.stage='Info';payload.assigned_to='Emma';updateRegistrationRequestDraft(form);registrationRequestStatus='Sending request...';renderRegistrationsPage();var params=Object.keys(payload).map(function(key){return encodeURIComponent(key)+'='+encodeURIComponent(payload[key]||'')}).join('&');jsonp(CITADEL_API_URL+'?action=saveRegistrationRequest&'+params).then(function(response){if(!response||!response.ok)throw new Error(response&&response.error?response.error:'Save failed');registrationRequestDraft={};registrationRequestStatus='Ready';showSubmissionToast('Submission Has Been Sent To Compliance Team');loadRegistrationsData()}).catch(function(error){registrationRequestStatus=error.message||'Save failed';renderRegistrationsPage()})}
function collectRegistrationPanelPayload(selected){var payload={request_id:selected.id};Array.from(pagePanel.querySelectorAll('[data-registration-input]')).forEach(function(field){payload[field.getAttribute('data-registration-input')]=field.value});return payload}
function runRegistrationAction(action){var selected=registrationsData.requests[registrationsData.selectedIndex]||{};if(!selected.id)return;var today=todayInputValue();var payload={request_id:selected.id};if(action==='received'){payload.status='Open';payload.stage='Info';payload.received_date=today;registrationDetailView='dates'}else if(action==='researched'){payload.status='Open';payload.stage='Research';payload.researched_date=today;registrationDetailView='notes';Object.assign(payload,collectRegistrationPanelPayload(selected))}else if(action==='submitted-license'){payload.status='Pending';payload.stage='Submitted';payload.submitted_license_date=today;registrationDetailView='notes'}else if(action==='move-active'){payload.status='Active';payload.stage='Active';payload.active='true';payload.license_received_date=today;Object.assign(payload,collectRegistrationPanelPayload(selected));registrationDetailView='license'}else if(action==='archive'){payload.status='Archived';payload.stage='Archived';payload.active='false';payload.archived_date=today}else if(action==='restore-new'){payload.status='New';payload.stage='Info';payload.active='true';registrationDetailView='info'}else if(action==='save-panel'){Object.assign(payload,collectRegistrationPanelPayload(selected))}updateRegistrationRequest(payload)}
function updateRegistrationRequest(payload){if(!CITADEL_API_URL){registrationsLoadStatus='Registration sheet not connected yet';renderRegistrationsPage();return}registrationsLoadStatus='Saving...';renderRegistrationsPage();var params=Object.keys(payload).map(function(key){return encodeURIComponent(key)+'='+encodeURIComponent(payload[key]||'')}).join('&');jsonp(CITADEL_API_URL+'?action=updateRegistrationRequest&'+params).then(function(response){if(!response||!response.ok)throw new Error(response&&response.error?response.error:'Save failed');showSubmissionToast('Registration workflow updated');loadRegistrationsData()}).catch(function(error){registrationsLoadStatus=error.message||'Save failed';renderRegistrationsPage()})}
function renderStandardFilterCard(pageId){var filters=STANDARD_FILTERS[pageId]||STANDARD_FILTERS.tasks;return '<section class="standard-filter-card"><div><h3>Filters + Sort + Search</h3><p>Refine and find records the same way on every page</p></div><button type="button" data-standard-report>Reports</button><div class="standard-filters">'+filters.map(function(item){return '<label>'+escapeHtml(item[0])+'<select>'+renderSelectOptions(item[1],item[2],item[1])+'</select></label>'}).join('')+'<label>Search<input type="search" placeholder="Search this view"></label></div></section>'}

function bindStandardPage(){if(standardPageEventsBound)return;standardPageEventsBound=true;pagePanel.addEventListener("click",function(event){if(activePage==="command-center"||activePage==="liens"||activePage==="contractors")return;var metric=event.target.closest("[data-standard-metric]");if(metric){activeStandardMetric=metric.getAttribute("data-standard-metric")||"";renderStandardContent();return}if(event.target.closest("[data-standard-report]")){openStandardReportsModal();return}})}
function renderStandardContent(){var details=pageDetails[activePage]||pageDetails.tasks;var label=getPageLabel(activePage);pagePanel.className="page-panel standard-page";pagePanel.innerHTML=renderModuleStatusLine('Stable')+'<div id="subTabs" class="sub-tabs" hidden></div><div class="metric-grid">'+([["Open Alerts","0","Alerts + follow-ups"]].concat(details.metrics)).map(function(item){return '<button type="button" class="metric-card standard-metric-button '+(activeStandardMetric===item[0]?'active':'')+'" data-standard-metric="'+escapeHtml(item[0])+'"><div class="metric-label">'+escapeHtml(item[0])+'</div><div class="metric-value">'+escapeHtml(item[1])+'</div><div class="metric-note">'+escapeHtml(item[2])+'</div></button>'}).join('')+'</div>'+renderStandardFilterCard(activePage)+'<div class="content-grid"><article class="work-card"><div class="card-heading"><h3>'+escapeHtml(label)+' Focus</h3><span>'+(activePage.indexOf("fleet")===0?"Fleet":"Today")+'</span></div><p id="focusCopy">'+escapeHtml(details.focus)+'</p></article><article class="work-card compact"><div class="card-heading"><h3>Queue Snapshot</h3><span>Priority</span></div><ul class="queue-list">'+details.queue.map(function(item){return '<li><span>'+escapeHtml(item[0])+'</span><strong>'+escapeHtml(item[1])+'</strong></li>'}).join('')+'</ul></article></div>';subTabs=document.querySelector("#subTabs");renderSubTabs()}

function loadLiensData(){if(!CITADEL_API_URL){liensLoading=false;return}if(!liensData.records.length)hydrateLiensFromCache();liensLoading=true;liensLoadError="";if(activePage==="liens"&&!liensData.records.length)renderContent();jsonp(CITADEL_API_URL+"?action=getLiens").then(function(response){if(!response||!response.ok||!response.data)throw new Error(response&&response.error?response.error:"No liens data returned");applyLiensPayload(response.data);saveLiensCache(response.data);liensLoading=false;if(activePage==="liens"||activePage==="command-center")renderContent()}).catch(function(error){liensLoading=false;liensLoadError="Unable to refresh lien records";console.warn("Liens sheet load failed",error);if(activePage==="liens")renderContent()})}
function jsonp(url){return new Promise(function(resolve,reject){var callback="citadelCallback"+Date.now()+Math.floor(Math.random()*10000);var script=document.createElement("script");var timeout=window.setTimeout(function(){cleanup();reject(new Error("Sheet request timed out"))},45000);function cleanup(){window.clearTimeout(timeout);delete window[callback];if(script.parentNode)script.parentNode.removeChild(script)}window[callback]=function(payload){cleanup();resolve(payload)};script.onerror=function(){cleanup();reject(new Error("Sheet request failed"))};script.src=url+"&callback="+callback;document.head.appendChild(script)})}
function loadContractorsData(){if(!CITADEL_API_URL){contractorsLoading=false;return}if(!contractorsData.records.length)hydrateContractorsFromCache();contractorsLoading=true;contractorsLoadError="";if(activePage==="contractors"&&!contractorsData.records.length)renderContent();jsonp(CITADEL_API_URL+"?action=getContractors").then(function(response){if(!response||!response.ok||!response.data)throw new Error(response&&response.error?response.error:"No contractor data returned");applyContractorsPayload(response.data);saveContractorsCache(response.data);contractorsLoading=false;if(activePage==="contractors"||activePage==="command-center")renderContent()}).catch(function(error){contractorsLoading=false;contractorsLoadError="Contractors sheet not connected yet";console.warn("Contractors sheet load failed",error);if(activePage==="contractors")renderContent()})}

function renderContent(){var label=getPageLabel(activePage);pageTitle.textContent=label;if(activePage==="command-center"){renderCommandCenter();bindCommandCenter();return}if(activePage==="region-health"){renderRegionHealthPage();bindStandardPage();return}if(activePage==="liens"){renderLiensPage();bindLiensPage();return}if(activePage==="contractors"){renderContractorsPage();bindContractorsPage();return}if(activePage==="registrations"){activePage="registration-request";setActiveNav();renderContent();return}if(activePage==="registration-request"||activePage==="registration-open"||activePage==="registration-active"||activePage==="registration-archived"){renderRegistrationsPage();bindRegistrationsPage();if(!registrationsData.requests.length&&!registrationsLoading&&!registrationsLoadStatus)loadRegistrationsData();return}if(activePage==="reviews"){renderReviewsPage();bindReviewsPage();if(!reviewsData.records.length&&!reviewsLoading&&!reviewsLoadError)loadReviewsData();return}if(activePage==="pricing"){renderPricingPage();bindPricingPage();if(!pricingState.rows.length&&!pricingState.loading&&!pricingState.error)loadPricingData();return}if(activePage==="fleet"||activePage==="fleet-vehicles"||activePage==="fleet-drivers"){renderFleetPage();bindFleetPage();if(!fleetData.sourceRows.length&&!fleetData.vehicles.length&&!fleetData.drivers.length&&!fleetLoading&&!fleetLoadError)loadFleetData();return}renderStandardContent();bindStandardPage()}
function setActivePage(pageId){activePage=pageId;renderNavigation();renderContent()}

initSettingsMenu();initForceRefreshButton();checkForCitadelUpdate();hydrateLiensFromCache();hydrateContractorsFromCache();hydrateReviewsFromCache();hydrateFleetFromCache();setActivePage(activePage);loadLiensData();loadContractorsData();loadReviewsData();loadFleetData();
